/**
 * Map indexée par id pour lookup O(1)
 * Usage : BUILDING_DEFINITIONS_MAP.get('Building_EarlyGothicEra_Home_Small_1')
 */
export const BUILDING_DEFINITIONS_MAP = new Map<string, BuildingDef>(
  BUILDING_DEFINITIONS.map(b => [b.id, b])
);

/**
 * Map indexée par groupe pour retrouver les tailles depuis roc-helper
 * Usage : BUILDING_SIZE_BY_GROUP.get('smallHome') → { width: 2, height: 2 }
 * Note : un groupe peut avoir plusieurs tailles (selon le niveau),
 *        on retourne la taille du niveau 1 par défaut.
 */
export const BUILDING_SIZE_BY_GROUP = new Map<string, { width: number; height: number }>(
  BUILDING_DEFINITIONS
    .filter(b => b.group && (b.level === 1 || b.level == null))
    .map(b => [b.group, { width: b.width, height: b.height }])
);

/** Retourne les bâtiments disponibles pour une ville */
export function getBuildingsForCity(cityId: string): BuildingDef[] {
  return BUILDING_DEFINITIONS.filter(b => b.cities.includes(cityId));
}

/** Retourne la taille d'un bâtiment depuis son groupe roc-helper */
export function getBuildingSizeByGroup(group: string): { width: number; height: number } {
  return BUILDING_SIZE_BY_GROUP.get(group) ?? { width: 1, height: 1 };
}
